  fn insert_bookmark(&self, data: BookmarkData) -> Result<i64> {
    let sql = format!(
      "INSERT INTO bookmark ({}) VALUES ({ })",
      "uri,title,notes,creation_context",
      "?,?,?,?"
    );
    let mut stmt = self.conn.prepare(sql)?;
    
    stmt.bind((1, sql::Value::String(data.uri.to_string())))?;
    stmt.bind((2, sql::Value::String(data.title.to_string())))?;
    stmt.bind((3, sql::Value::String(data.notes.to_string())))?;
    stmt.bind((4, sql::Value::String(data.creation_context.to_string())))?;
    stmt.next()?;
    
    // Get the last inserted ID
    let mut stmt = self.conn.prepare("SELECT last_insert_rowid()")?;
    let id: i64 = if let Some(row) = stmt.into_iter().next() {
      row?.read(0)
    } else {
      return Err(Error::Other("Failed to get last insert ID".into()));
    };
    Ok(id)
  }
  
  fn get_bookmark_by_id(&self, id: i64) -> Result<Option<BookmarkData>> {
    let mut stmt = self.conn.prepare(
      "SELECT * FROM bookmark WHERE id = ?1"
    )?;
    stmt.bind((1, sql::Value::Integer(id)))?;
    
    if let Some(row) = stmt.into_iter().next() {
      let row = row?;
      Ok(Some(self.row_to_bookmark(&row)?))
    } else {
      Ok(None)
    }
  }
  
  fn get_bookmark_by_url(&self, url: &str) -> Result<Option<BookmarkData>> {
    let mut stmt = self.conn.prepare(
      "SELECT * FROM bookmark WHERE uri = ?1"
    )?;
    stmt.bind((1, sql::Value::String(url.to_string())))?;
    
    if let Some(row) = stmt.into_iter().next() {
      let row = row?;
      Ok(Some(self.row_to_bookmark(&row)?))
    } else {
      Ok(None)
    }
  }
  
  /// List Bookmarks with dynamic filtering using sea-query
  fn list_bookmarks(&self, limit: Option<usize>, offset: Option<usize>, filter: &BookmarkFilter) -> Result<Vec<BookmarkData>> {
    // Build query with sea-query
    let mut query = Query::select();
    query
      .column(BookmarkIden::Id)
      .column(BookmarkIden::Uri)
      .column(BookmarkIden::Title)
      .column(BookmarkIden::Notes)
      .column(BookmarkIden::CreationContext)
      .column(BookmarkIden::CreatedAt)
      .from(BookmarkIden::Table);
    
    // Add filter conditions
    let cond = filter.to_condition();
    if !cond.is_empty() {
      query.cond_where(cond);
    }
    
    // Add ordering (by created_at/seen_at desc, or first column if no time field)
    query.order_by(BookmarkIden::CreatedAt, sea_query::Order::Desc);
    
    // Add limit and offset
    if let Some(l) = limit {
      query.limit(l as u64);
    }
    if let Some(o) = offset {
      query.offset(o as u64);
    }
    
    // Build SQL
    let (sql, _values) = query.build(SqliteQueryBuilder);
    
    // Execute with sqlite crate
    let mut stmt = self.conn.prepare(&sql)?;
    let mut results = Vec::new();
    for row in stmt.into_iter() {
      let row = row?;
      results.push(self.row_to_bookmark(&row)?);
    }
    Ok(results)
  }
  
  fn update_bookmark(&self, id: i64, data: BookmarkData) -> Result<bool> {
    let mut stmt = self.conn.prepare(
      r#"
      UPDATE bookmark SET
        uri = ?1,
        title = ?2,
        notes = ?3,
        creation_context = ?4
      WHERE id = ?5
      "#
    )?;
    
    stmt.bind((1, sql::Value::String(data.uri.to_string())))?;
    stmt.bind((2, sql::Value::String(data.title.to_string())))?;
    stmt.bind((3, sql::Value::String(data.notes.to_string())))?;
    stmt.bind((4, sql::Value::String(data.creation_context.to_string())))?;
    stmt.bind((5, sql::Value::Integer(id)))?;
    
    stmt.next()?;
    Ok(self.conn.change_count() > 0)
  }
  
  fn update_bookmark_title(&self, id: i64, title: Option<string>) -> Result<bool> {
    let mut stmt = self.conn.prepare(
      "UPDATE bookmark SET title = ?1 WHERE id = ?2"
    )?;
    stmt.bind((1, sql::Value::String(title.to_string())))?;
    stmt.bind((2, sql::Value::Integer(id)))?;
    stmt.next()?;
    Ok(self.conn.change_count() > 0)
  }
  
  fn update_bookmark_notes(&self, id: i64, notes: Option<string>) -> Result<bool> {
    let mut stmt = self.conn.prepare(
      "UPDATE bookmark SET notes = ?1 WHERE id = ?2"
    )?;
    stmt.bind((1, sql::Value::String(notes.to_string())))?;
    stmt.bind((2, sql::Value::Integer(id)))?;
    stmt.next()?;
    Ok(self.conn.change_count() > 0)
  }
  
  fn delete_bookmark(&self, id: i64) -> Result<bool> {
    let mut stmt = self.conn.prepare("DELETE FROM bookmark WHERE id = ?1")?;
    stmt.bind((1, sql::Value::Integer(id)))?;
    stmt.next()?;
    Ok(self.conn.change_count() > 0)
  }
  
  fn row_to_bookmark(&self, row: &sql::Row) -> Result<BookmarkData> {
    Ok(BookmarkData {
      id: row.try_read::<i64, _>("id")?,
      uri: row.try_read::<string, _>("uri")?,
      title: row.try_read::<Option<string>, _>("title")?,
      notes: row.try_read::<Option<string>, _>("notes")?,
      creation_context: {
        let s = row.try_read::<&str, _>("creation_context")?;
        serde_json::from_str(s).map_err(|e| Error::Other(format!("JSON parse error: {}", e)))?
      },
      created_at: row.try_read::<i64, _>("created_at")?,
    })
  }
