  fn insert_media(&self, data: MediaData) -> Result<i64> {
    let sql = format!(
      "INSERT INTO media ({}) VALUES ({ })",
      "content_hash,mime_type,uri,width,height,duration_ms,metadata",
      "?,?,?,?,?,?,?"
    );
    let mut stmt = self.conn.prepare(sql)?;
    
    stmt.bind((1, sql::Value::String(data.content_hash.to_string())))?;
    stmt.bind((2, sql::Value::String(data.mime_type.to_string())))?;
    stmt.bind((3, sql::Value::String(data.uri.to_string())))?;
    stmt.bind((4, sql::Value::String(data.width.to_string())))?;
    stmt.bind((5, sql::Value::String(data.height.to_string())))?;
    stmt.bind((6, sql::Value::String(data.duration_ms.to_string())))?;
    stmt.bind((7, data.metadata.as_ref().map(|v| sql::Value::String(v.to_string()))))?;
    stmt.next()?;
    
    // Get the last inserted ID
    let mut stmt = self.conn.prepare("SELECT last_insert_rowid()")?;
    let id: i64 = if let Some(row) = stmt.into_iter().next() {
      row?.read(0)
    } else {
      return Err(Error::Other("Failed to get last insert ID".into()));
    };
    Ok(id)
  }
  
