  /// List Medias with dynamic filtering using sea-query
  fn list_medias(&self, limit: Option<usize>, offset: Option<usize>, filter: &MediaFilter) -> Result<Vec<MediaData>> {
    // Build query with sea-query
    let mut query = Query::select();
    query
      .column(MediaIden::Id)
      .column(MediaIden::ContentHash)
      .column(MediaIden::MimeType)
      .column(MediaIden::Uri)
      .column(MediaIden::Width)
      .column(MediaIden::Height)
      .column(MediaIden::DurationMs)
      .column(MediaIden::Metadata)
      .column(MediaIden::CreatedAt)
      .from(MediaIden::Table);
    
    // Add filter conditions
    let cond = filter.to_condition();
    if !cond.is_empty() {
      query.cond_where(cond);
    }
    
    // Add ordering (by created_at/seen_at desc, or first column if no time field)
    query.order_by(MediaIden::CreatedAt, sea_query::Order::Desc);
    
    // Add limit and offset
    if let Some(l) = limit {
      query.limit(l as u64);
    }
    if let Some(o) = offset {
      query.offset(o as u64);
    }
    
    // Build SQL
    let (sql, _values) = query.build(SqliteQueryBuilder);
    
    // Execute with sqlite crate
    let mut stmt = self.conn.prepare(&sql)?;
    let mut results = Vec::new();
    for row in stmt.into_iter() {
      let row = row?;
      results.push(self.row_to_media(&row)?);
    }
    Ok(results)
  }
  
