  fn insert_post(&self, data: PostData) -> Result<i64> {
    let sql = format!(
      "INSERT INTO post ({}) VALUES ({ })",
      "bits,content_hash,author_did,signature",
      "?,?,?,?"
    );
    let mut stmt = self.conn.prepare(sql)?;
    
    stmt.bind((1, sql::Value::String(data.bits.to_string())))?;
    stmt.bind((2, sql::Value::String(data.content_hash.to_string())))?;
    stmt.bind((3, sql::Value::String(data.author_did.to_string())))?;
    stmt.bind((4, sql::Value::String(data.signature.to_string())))?;
    stmt.next()?;
    
    // Get the last inserted ID
    let mut stmt = self.conn.prepare("SELECT last_insert_rowid()")?;
    let id: i64 = if let Some(row) = stmt.into_iter().next() {
      row?.read(0)
    } else {
      return Err(Error::Other("Failed to get last insert ID".into()));
    };
    Ok(id)
  }
  
