// Schema Migrations
// ============================================================================

impl DbActor {
  fn migrate_entities(conn: &sql::ConnectionThreadSafe) -> Result<()> {
    // Bookmark table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS bookmark (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        uri TEXT NOT NULL,
        title TEXT,
        notes TEXT,
        creation_context TEXT NOT NULL,
        created_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_bookmark_url ON bookmark(uri)")?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_bookmark_created ON bookmark(created_at)")?;
    // Conversation table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS conversation (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT,
        content TEXT NOT NULL,
        attributed_to TEXT,
        capture_time TEXT NOT NULL,
        first_entry_time TEXT,
        last_entry_time TEXT,
        source_url TEXT,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_conversation_created ON conversation(created_at)")?;
    // Media table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS media (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        content_hash TEXT,
        mime_type TEXT NOT NULL,
        uri TEXT NOT NULL,
        width TEXT,
        height TEXT,
        duration_ms TEXT,
        metadata TEXT,
        created_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_media_url ON media(uri)")?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_media_created ON media(created_at)")?;
    // MediaSource table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS media_source (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        url TEXT NOT NULL,
        adapter_type TEXT NOT NULL,
        cursor_state TEXT,
        capabilities TEXT NOT NULL,
        config TEXT,
        last_polled_at TEXT,
        last_error TEXT,
        is_active TEXT NOT NULL,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_media_source_url ON media_source(url)")?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_media_source_created ON media_source(created_at)")?;
    // Person table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS person (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        display_name TEXT NOT NULL,
        handle TEXT,
        avatar_media_id TEXT,
        metadata TEXT,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_person_created ON person(created_at)")?;
    // Post table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS post (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        bits TEXT NOT NULL,
        content_hash TEXT,
        author_did TEXT,
        signature TEXT,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_post_created ON post(created_at)")?;
    // StreamEntry table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS stream_entry (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        seen_at TEXT NOT NULL,
        person_id TEXT,
        post_id TEXT,
        media_id TEXT,
        bookmark_id TEXT,
        conversation_id TEXT,
        directory TEXT,
        kind TEXT,
        content_hash TEXT,
        created_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_stream_entry_created ON stream_entry(created_at)")?;
    // View table
    conn.execute(
      r#"
      CREATE TABLE IF NOT EXISTS view (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        index TEXT NOT NULL,
        label TEXT,
        badge TEXT NOT NULL,
        filters TEXT NOT NULL,
        sort_by TEXT NOT NULL,
        is_pinned TEXT NOT NULL,
        is_thestream TEXT NOT NULL,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL
      )
      "#
    )?;
    conn.execute("CREATE INDEX IF NOT EXISTS idx_view_created ON view(created_at)")?;
    Ok(())
  }
}
